INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 1.47, 1, 2002, "クローチェ", 10001, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 1, 126401, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 2.15, 1, 2002, "クローチェ", 10002, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2, 126401, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 0.0, 1, 2002, "ライラエル", 10003, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2, 126501, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 0.0, 1, 2002, "ライラエル", 10004, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 1, 126501, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2, 2002, "リンド", 10005, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2, 127702, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2, 2002, "リンド", 10006, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2, 127702, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2, 2002, "ヴルム", 10007, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 1, 127802, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 6.5, 2, 2002, "ヴルム", 10008, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2, 127802, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 3, 2002, "アネモネ", 10009, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2, 129602, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 3, 2002, "アネモネ", 10010, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2, 129602, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 3, 2002, "ネフィ=ネラ", 10011, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 1, 129701, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 6.2, 3, 2002, "ネフィ=ネラ", 10012, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2, 129701, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (5, 0.0, -470.0, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 3.1, 4, 2002, "カノン", 10013, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 3, 130301, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 6.15, 4, 2002, "カノン", 10014, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 3, 130301, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 0.0, 4, 2002, "ナーナ", 10015, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2, 130401, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 3.35, 4, 2002, "ナーナ", 10016, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2, 130401, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 0.0, 5, 2002, "ホウオウ", 10017, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 1, 130502, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 3.18, 5, 2002, "ホウオウ", 10018, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2, 130502, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (4, 0.0, -470.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 0.0, 5, 2002, "ホウオウ", 10019, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 4, 130503, 3);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 4.9, 5, 2002, "ネア", 10020, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 1, 123301, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 4.8, 5, 2002, "ネア", 10021, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 1, 123301, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 4.922, 6, 2002, "カリザ", 10022, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 3, 133301, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (5, 0.0, -470.0, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 9.638, 6, 2002, "カリザ", 10023, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 3, 133301, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 2.88, 6, 2002, "ミーア", 10024, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 1, 133401, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 4.818, 6, 2002, "ミーア", 10025, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 5, 133401, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 1.78, 7, 2002, "グレイス", 10026, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2, 133002, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (7, 0.0, -470.0, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 6.15, 7, 2002, "グレイス", 10027, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 1, 133002, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 4.28, 7, 2002, "ヴァイオレット", 10028, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 6, 133102, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 0.0, 7, 2002, "ヴァイオレット", 10029, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 1, 133102, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 5.53, 8, 2002, "ルルィ", 10030, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2, 136902, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (7, 0.0, -470.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 6.05, 8, 2002, "ルルィ", 10031, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 9, 136902, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 0.0, 8, 2002, "デュラン", 10032, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2, 137001, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 0.0, 8, 2002, "デュラン", 10033, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2, 137001, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 0.0, 9, 2002, "サツキ", 10034, "おう\n好きなもん持ってきな", 2, 135902, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (6, 0.0, -470.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 4.935, 9, 2002, "サツキ", 10035, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 1, 135902, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (5, 0.0, -470.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 7.441, 9, 2002, "ユキノ", 10036, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2, 135802, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (7, 0.0, -470.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 0.0, 9, 2002, "ユキノ", 10037, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 7, 135802, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 2.295, 10, 2002, "クルル", 10038, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2, 130901, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (6, 0.0, -470.0, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 6.281, 10, 2002, "クルル", 10039, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 1, 130901, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 5.549, 10, 2002, "ヴォルガーノ", 10040, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2, 137701, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (6, 0.0, -470.0, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 2.64, 10, 2002, "ヴォルガーノ", 10041, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 3, 137701, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (4, 0.0, -470.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 7.642, 11, 2002, "ライラエル", 10042, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 7, 132801, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 0.0, 11, 2002, "ライラエル", 10043, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 1, 132802, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 0.0, 11, 2002, "クローチェ", 10044, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 1, 134502, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 3.72, 11, 2002, "クローチェ", 10045, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2, 134501, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (1, 0.0, -470.0, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 4.991, 12, 2002, "ネフィ＝ネラ", 10046, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2, 138201, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (4, 0.0, -470.0, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 3.877, 12, 2002, "ネフィ＝ネラ", 10047, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 1, 138201, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (6, 0.0, -470.0, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 1.71, 12, 2002, "アラクネ", 10048, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 4, 136001, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 5.32, 12, 2002, "アラクネ", 10049, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 5, 136001, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (4, 0.0, -470.0, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 3.727, 13, 2002, "アネモネ", 10050, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 9, 135401, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (9, 0.0, -470.0, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 7.213, 13, 2002, "アネモネ", 10051, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 7, 135401, 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 1.874, 13, 2002, "クリア", 10052, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 1, 135301, 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (2, 0.0, -470.0, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 0.0, 13, 2002, "クリア", 10053, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 2, 135301, 2);
